const ICON_MAP = Object.values(ICON_DB)
  .flat()
  .reduce(
    (acc, icon) => {
      acc[icon.id] = icon;
      return acc;
    },
    {} as Record<string, { svg: React.ReactNode; viewBox?: string }>,
  );

const FALLBACK_ICON = {
  svg: (
    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
  ),
  viewBox: "0 0 24 24",
};

export function useCustomSvgIcons() {
  const getCategoryIcons = (type: ItemType) => ICON_DB[type] || [];

  const getSpecificIcon = (id: string) => ICON_MAP[id] || FALLBACK_ICON;

  return { getCategoryIcons, getSpecificIcon };
}
